{
  "summary": "This paper proposes Contrastive Novelty Learning (CNL), a method that leverages large language models to generate semantically novel out-of-distribution examples for open-set selective classification in text. By combining a novel example generation process (Novelty Prompting) with a contrastive confidence loss, CNL improves selective prediction and OOD detection without sacrificing in-distribution accuracy.",
  "strengths": [
    {
      "point": "Innovative use of LLMs to generate semantically novel OOD examples",
      "evidence": "Novelty Prompting uses GPT-3 and GPT-J to generate novel class labels and corresponding examples that are plausible and semantically distinct from ID classes."
    },
    {
      "point": "Contrastive Confidence Loss (CCL) effectively calibrates confidence",
      "evidence": "CCL encourages lower confidence on OOD examples relative to ID examples without forcing uniform confidence, preserving ID accuracy and improving selective prediction."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple datasets and baselines",
      "evidence": "Experiments on 14 splits from 4 NLP datasets show consistent improvements in AUAC and AUROC over strong baselines, with ablations demonstrating robustness to generation scale and model size."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent generative OOD detection methods leveraging LLMs",
      "evidence": "The paper does not compare against recent GPT-based paraphrasing or controlled generation methods for OOD synthesis, weakening novelty claims."
    },
    {
      "point": "Insufficient methodological details and reproducibility information",
      "evidence": "Missing exact LLM prompt templates, sampling parameters, and training hyperparameters for CCL optimization limit reproducibility."
    },
    {
      "point": "Limited evaluation metrics and baselines for selective prediction",
      "evidence": "Only AUAC and AUROC are reported; other metrics like calibration error or selective risk at fixed coverage are missing, and strong baselines such as energy-based or ensemble uncertainty methods are omitted."
    },
    {
      "point": "Unclear operationalization and justification of synonym filtering and confidence definition",
      "evidence": "No clear criteria for synonym detection or explicit definition of 'confidence' used in CCL, causing ambiguity in method interpretation."
    },
    {
      "point": "Limited discussion on scalability, generalizability, and dataset-specific challenges",
      "evidence": "No analysis on scalability to large label spaces, impact of class imbalance, or extension beyond text classification; TACRED dataset challenges remain underexplored."
    }
  ],
  "questions": [
    {
      "question": "How does CNL compare to other recent LLM-based generative OOD detection methods?",
      "motivation": "Understanding relative novelty and effectiveness requires benchmarking against state-of-the-art generative approaches."
    },
    {
      "question": "What are the exact prompting strategies and hyperparameters used for LLM generation and CCL training?",
      "motivation": "Detailed methodological transparency is essential for reproducibility and adoption by the community."
    },
    {
      "question": "How does CNL perform under class imbalance and in tasks beyond text classification?",
      "motivation": "Evaluating robustness and generalizability is critical for real-world applicability."
    },
    {
      "question": "Can the synonym filtering and confidence measures be better defined or validated?",
      "motivation": "Clear operational definitions would strengthen the methodological rigor and interpretability of results."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
